public class InsufficientStockException extends RuntimeException {
    private final int requested;
    private final int available;

    public InsufficientStockException(int requested, int available) {
        super(String.format("Insufficient stock: requested %d but only %d available",
                            requested, available));
        this.requested = requested;
        this.available = available;
    }

    public int getRequested() { return requested; }
    public int getAvailable() { return available; }
}

// Usage:
class Inventory {
    private int stock = 10;

    public void withdraw(int qty) {
        if (qty > stock) throw new InsufficientStockException(qty, stock);
        stock -= qty;
    }
}

// Caller:
try {
    inventory.withdraw(15);
} catch (InsufficientStockException e) {
    System.out.println(e.getMessage());
    System.out.println("Available: " + e.getAvailable());
}
```

